args.sparql:
SELECT ?winner WHERE {
  ?match wdt:P31 wd:Q16599022 ;
         rdfs:label 'Women\'s Royal Rumble match'@en .
  ?match wdt:P585 ?time .
  ?match wdt:P166 ?winner .
  SERVICE wikidata:label {
    bd:serviceParam wikibase:language 'en'
  }
  FILTER(STR(?time) >= '2023-01-01')  # Only consider recent matches
} ORDER BY DESC(?time)
LIMIT 1

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?winner
WHERE {
  ?match wdt:P31 wd:Q16599022 ;
         rdfs:label "Women's Royal Rumble match"@en ;
         wdt:P585 ?time ;
         wdt:P166 ?winner .
  FILTER(STR(?time) >= "2023-01-01")
}
ORDER BY DESC(?time)
LIMIT 1

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?winner WHERE {
  ?event wdt:P585 ?time ;
         wdt:P31 wd:Q36103 ;
         wdt:P1450 ?match .
  ?match wdt:P31 wd:Q16599022 ;
         rdfs:label ?matchLabel ;
         wdt:P166 ?winner .
  FILTER(LCASE(?matchLabel) LIKE '%women%')
  FILTER(STR(?time) >= '2020-01-01')
}
ORDER BY DESC(?time)
LIMIT 1

